INSERT INTO public.hardware_component (id, project_id, name, manufacturer, model, version, status, description, created_by, created_at, updated_at, function_block, min_can_id_offset, bus_protocol) VALUES (29, NULL, 'Kreisel BMS String (Debug PCAN)', 'Kreisel Electric', 'Battery BMS', NULL, 'DRAFT', 'Kreisel Electric battery string — per-string data on the debug PCAN bus. Instantiate once per BMS node (01/05/09/13/17/21/25/29). CAN ID offset per node: +0=01, +1=05, +2=09, +3=13, +4=17, +5=21, +6=25, +7=29. SlowDataMpex (0x190) uses mux (page index byte).', NULL, '2026-03-10 20:11:23.724', '2026-03-10 20:11:23.724', NULL, 529, 'CANBUS') ON CONFLICT DO NOTHING;
